import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.Files;
import java.io.IOException;
import java.util.Scanner;

public class PathTraversalSecure {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter file name: ");
        String fileName = scanner.nextLine();

        try {
            Path filePath = Paths.get("resources", fileName).normalize().toAbsolutePath();

            if (!filePath.startsWith(Paths.get("resources").toAbsolutePath())) {
                System.out.println("Access to this file is not allowed.");
                return;
            }

            byte[] data = Files.readAllBytes(filePath);
            System.out.println(new String(data));
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

